async function main () {
  const fastify = require('fastify')()

  await fastify.register(fastifyThrottle, {
    bytesPerSecond: 10000,
    streamPayloads: true,
    stringPayloads: true,
    bufferPayloads: true
  })

  fastify.get('/string', (_req, reply) => {
    reply.send(Buffer.allocUnsafe(1024 * 1024).toString('ascii'))
  })

  fastify.get('/buffer', (_req, reply) => {
    reply.send(Buffer.allocUnsafe(1024 * 1024))
  })

  fastify.get('/stream', (_req, reply) => {
    reply.send(new RandomStream(30000))
  })

  fastify.get('/delayed', {
    config: {
      throttle: {
        bytesPerSecond: function (elapsedTime, _bytes) {
          if (elapsedTime < 2) {
            return 0
          } else {
            return Infinity
          }
        }
      }
    }
  }, (_req, reply) => {
    reply.send(createReadStream(resolve(__dirname, __filename)))
  })

  fastify.get('/pojo', (_req, reply) => {
    const payload = Array(10000).fill(0).map(() => (Math.random() * 1e6).toString(36))
    reply.send({ payload })
  })

  fastify.listen({ port: 3000 }, (err, address) => {
    if (err) {
      console.error(err)
    }
    console.log(address)
  })
}

(schemaProperties: Record<string, JSONSchema7Extended>): JSONSchema7 => ({
  definitions: {
    entity: {
      type: 'object',
      properties: Object.keys(schemaProperties)
        .filter(key => !schemaProperties[key]._options?.hidden)
        .reduce((props, key) => ({ ...props, [key]: schemaProperties[key] }), {}),
      required: Object.keys(schemaProperties)
