write(data, _, cb = noop) {
  if (this.destroyed) throw new ERR_STREAM_DESTROYED()

  if (this[kClientError] && data.startsWith('HTTP/')) {
    const [header, body] = data.split('\r\n\r\n')
    const [first, ...headers] = header.split('\r\n')
    const [,code, statusText] = first.split(' ')
    this[kHead] = {
      headers: headers.map((header) => {
        const [name, ...value] = header.split(': ')
        return { name, value: value.join(': ').trim() }
      }).filter(header => header.name.toLowerCase() !== 'content-length'),
      status: `${code} ${statusText}`,
    }
    data = body
    return this.end(data, _, cb)
  }

  const res = this[kRes]

  this[kReadyState].write = true

  res.cork(() => {
    if (this[kHead]) {
      writeHead(res, this[kHead])
      this[kHead] = null
    }

    const drained = res.write(getChunk(data))
    this.bytesWritten += byteLength(data)

    if (drained) return cb()
    drain(this, cb)
  })

  return !this.writableNeedDrain
}

(jsonSchema: JSONSchema.BaseSchema): OpenAPIV3.SchemaObject => {
  const clone: any = { ...jsonSchema }

  for (const key of [
    '$schema',
    '$id',
    'unevaluatedProperties',
    'dependentSchemas',
    'patternProperties',
    'propertyNames',
    'contentEncoding',
    'contentMediaType',
  ]) {
    delete clone[key]
  }

  const recursive = (v: any): any =>
    Array.isArray(v) ? v.map(jsonSchemaToOAS_3_0) : jsonSchemaToOAS_3_0(v)

  if (clone.properties) {
    for (const [k, v] of Object.entries(clone.properties)) {
      clone.properties![k] = jsonSchemaToOAS_3_0(v as any)
    }
  }

  if (clone.items && !Array.isArray(clone.items)) {
    clone.items = recursive(clone.items)
  }

  for (const key of ['allOf', 'anyOf', 'oneOf', 'not', 'then', 'else', 'if', 'contains']) {
    if (clone[key]) {
      clone[key] = recursive(clone[key])
    }
  }

  return clone as OpenAPIV3.SchemaObject
}
